CREATE TABLE sense_symbols (
    id          INTEGER PRIMARY KEY,
    file_id     INTEGER NOT NULL REFERENCES sense_files(id) ON DELETE CASCADE,
    name        TEXT    NOT NULL,
    qualified   TEXT    NOT NULL,
    kind        TEXT    NOT NULL,
    visibility  TEXT    DEFAULT 'public',
    -- receiver records a method's dispatch kind for languages that
    -- distinguish them: 'instance' (Ruby Class#m) or 'singleton'
    -- (Ruby Class.m / def self.m). Empty for non-methods and for
    -- languages that don't carry the distinction. Used by the resolver
    -- to keep an instance call from binding to a same-named singleton
    -- method (and vice-versa) in the unqualified-name fallback.
    receiver    TEXT    NOT NULL DEFAULT '',
    parent_id   INTEGER REFERENCES sense_symbols(id),
    line_start  INTEGER NOT NULL,
    line_end    INTEGER NOT NULL,
    docstring   TEXT,
    complexity  INTEGER,
    snippet     TEXT,
    name_parts  TEXT,
    -- (file_id, qualified) is the Index contract's natural key for Symbol
    -- upserts. Not in the definition doc but required for ON CONFLICT.
    UNIQUE (file_id, qualified)
);
CREATE INDEX idx_sense_symbols_name      ON sense_symbols (name);
CREATE INDEX idx_sense_symbols_qualified ON sense_symbols (qualified);
CREATE INDEX idx_sense_symbols_kind      ON sense_symbols (kind);
CREATE INDEX idx_sense_symbols_file_id   ON sense_symbols (file_id);
CREATE INDEX idx_sense_symbols_parent_id ON sense_symbols (parent_id);
CREATE TRIGGER sense_symbols_fts_insert
	 AFTER INSERT ON sense_symbols BEGIN
	     INSERT INTO sense_symbols_fts(rowid, name, qualified, docstring, snippet, name_parts)
	     VALUES (new.id, new.name, new.qualified, new.docstring, new.snippet, new.name_parts);
	 END;
CREATE TRIGGER sense_symbols_fts_delete
	 BEFORE DELETE ON sense_symbols BEGIN
	     INSERT INTO sense_symbols_fts(sense_symbols_fts, rowid, name, qualified, docstring, snippet, name_parts)
	     VALUES ('delete', old.id, old.name, old.qualified, old.docstring, old.snippet, old.name_parts);
	 END;
CREATE TRIGGER sense_symbols_fts_update
	 BEFORE UPDATE ON sense_symbols BEGIN
	     INSERT INTO sense_symbols_fts(sense_symbols_fts, rowid, name, qualified, docstring, snippet, name_parts)
	     VALUES ('delete', old.id, old.name, old.qualified, old.docstring, old.snippet, old.name_parts);
	 END;
CREATE TRIGGER sense_symbols_fts_update_after
	 AFTER UPDATE ON sense_symbols BEGIN
	     INSERT INTO sense_symbols_fts(rowid, name, qualified, docstring, snippet, name_parts)
	     VALUES (new.id, new.name, new.qualified, new.docstring, new.snippet, new.name_parts);
	 END;
CREATE TABLE sense_edges (
    id          INTEGER PRIMARY KEY,
    source_id   INTEGER REFERENCES sense_symbols(id) ON DELETE CASCADE,
    target_id   INTEGER NOT NULL REFERENCES sense_symbols(id) ON DELETE CASCADE,
    kind        TEXT    NOT NULL,
    file_id     INTEGER NOT NULL REFERENCES sense_files(id) ON DELETE CASCADE,
    line        INTEGER,
    confidence  REAL    DEFAULT 1.0
);
CREATE INDEX idx_sense_edges_source ON sense_edges (source_id, kind);
CREATE UNIQUE INDEX idx_sense_edges_unique ON sense_edges (source_id, target_id, kind, file_id);
CREATE INDEX idx_sense_edges_target ON sense_edges (target_id, kind, source_id);
